  <Stack direction="column" gap="400">
    <TagGroup.Root size="sm" aria-label="Small tags">
      <TagGroup.TagList>
        <TagGroup.Tag>Small</TagGroup.Tag>
        <TagGroup.Tag>Compact</TagGroup.Tag>
        <TagGroup.Tag>Dense</TagGroup.Tag>
      </TagGroup.TagList>
    </TagGroup.Root>

    <TagGroup.Root size="md" aria-label="Medium tags">
      <TagGroup.TagList>
        <TagGroup.Tag>Medium</TagGroup.Tag>
        <TagGroup.Tag>Standard</TagGroup.Tag>
        <TagGroup.Tag>Default</TagGroup.Tag>
      </TagGroup.TagList>
